// Only run on the first Monday of the month
const today = new Date();
if (today.getDate() > 7) {
  return [];
}
return [{ json: { run: true, report_month: today.toISOString().substring(0, 7) + '-01' } }];

const userId = $('Get Users With Data').item.json.user_id;
const reportMonth = $('Check First Monday').item.json.report_month;
const entries = $('Get Month Entries').all().map(i => i.json);

// Top pains (ranked by frequency)
const pains = entries.filter(e => e.dimension === 'pain')
  .slice(0, 10)
  .map(e => ({ text: e.text, frequency: e.frequency, trend: e.trend, persona: e.persona }));

// Emerging desires (rising trend first)
const desires = entries.filter(e => e.dimension === 'desire')
  .sort((a, b) => (a.trend === 'rising' ? -1 : 1) - (b.trend === 'rising' ? -1 : 1))
  .slice(0, 5)
  .map(e => ({ text: e.text, frequency: e.frequency, trend: e.trend, persona: e.persona }));

// Language shifts (rising or fading)
const langShifts = entries.filter(e => e.dimension === 'language' && e.trend !== 'stable')
  .slice(0, 5)
  .map(e => ({ term: e.text, previous_term: null, direction: e.trend === 'rising' ? 'emerging' : 'fading', persona: e.persona, first_seen: null }));

// Criteria shifts
const critShifts = entries.filter(e => e.dimension === 'criteria' && e.trend !== 'stable')
  .slice(0, 5)
  .map((e, idx) => ({ criterion: e.text, direction: e.trend === 'rising' ? 'rising' : 'falling', previous_rank: null, current_rank: idx + 1, evidence_count: e.frequency }));

const monthName = new Date(reportMonth).toLocaleDateString('en-US', { month: 'long', year: 'numeric' });
const title = `Market Pulse — ${monthName}`;

const md = `# ${title}\n\n**Period:** ${monthName}\n**Total Entries:** ${entries.length}\n\n---\n\n## Top Pains\n${pains.map((p, i) => `${i+1}. ${p.text} (${p.frequency}x, ${p.trend})`).join('\n') || 'None detected'}\n\n## Emerging Desires\n${desires.map(d => `- ${d.text} (${d.frequency}x, ${d.trend})`).join('\n') || 'None detected'}\n\n## Language Shifts\n${langShifts.map(s => `- [${s.direction}] ${s.term}`).join('\n') || 'None detected'}\n\n## Criteria Shifts\n${critShifts.map(s => `- [${s.direction}] ${s.criterion} (${s.evidence_count} signals)`).join('\n') || 'None detected'}\n\n---\n*Generated by Signal Plane VoC Research*`;

return [{
  json: {
    user_id: userId,
    report_month: reportMonth,
    title: title,
    content_json: JSON.stringify({ pains_count: pains.length, desires_count: desires.length, lang_shifts_count: langShifts.length, crit_shifts_count: critShifts.length }),
    content_md: md,
    top_pains: JSON.stringify(pains),
    emerging_desires: JSON.stringify(desires),
    language_shifts: JSON.stringify(langShifts),
    criteria_shifts: JSON.stringify(critShifts)
  }
}];
